1	//! Capture-corpus sweep — SPEC acceptance ladder rung 2 for R1.
2	//!
3	//! For every `main/message` / `main/rules` / `main/tactic` / `main/help`
4	//! response captured across the 81 crawl manifests, this test:
5	//!   1. reads the RAW envelope bytes (materialized by
6	//!      workspace/tools/extract_r1_raw.py into workspace/r1_raw/);
7	//!   2. decodes the `{html,title}` envelope and INVERTS the producer's skin —
8	//!      un-postprocessing the fragment into logical lines and slicing the
9	//!      opaque content out of the observed block skeleton;
10	//!   3. feeds the sliced content back through the producer and asserts the
11	//!      re-rendered response equals the captured bytes EXACTLY.
12	//!
13	//! This exercises the frame + postprocess + envelope over the whole corpus
14	//! without a prover. A second test replays the curated round-1 byte targets
15	//! (producers/round1/targets/) the same way.
16	//!
17	//! The inversion is intentionally strict (panics on any unexpected shape) so
18	//! a capture that deviates from the modeled skeleton fails loudly instead of
19	//! being skipped.
20	
21	use std::fs;
22	use std::path::PathBuf;
23	
24	use producers_clean::model::{Content, ContentPane, EmptyRender, HeadedBlock, HelpPane};
25	use producers_clean::section::HELP_STATIC_HTML;
26	use producers_clean::{render_content_pane, render_help_pane};
27	
28	fn workspace_path(rel: &str) -> PathBuf {
29	    PathBuf::from(env!("CARGO_MANIFEST_DIR")).join(rel)
30	}
31	
32	// ---------------------------------------------------------------------------
33	// Envelope decoding (strict: asserts the exact observed skeleton [S07][S08])
34	// ---------------------------------------------------------------------------
35	
36	/// Decode a JSON string starting after its opening quote; returns the decoded
37	/// text and the byte offset of the closing quote.
38	fn decode_json_string(s: &str) -> (String, usize) {
39	    let bytes = s.as_bytes();
40	    let mut out = String::new();
41	    let mut i = 0;
42	    loop {
43	        match bytes[i] {
44	            b'"' => return (out, i),
45	            b'\\' => {
46	                i += 1;
47	                match bytes[i] {
48	                    b'"' => out.push('"'),
49	                    b'\\' => out.push('\\'),
50	                    b'/' => out.push('/'),
51	                    b'n' => out.push('\n'),
52	                    b't' => out.push('\t'),
53	                    b'r' => out.push('\r'),
54	                    b'b' => out.push('\u{8}'),
55	                    b'f' => out.push('\u{c}'),
56	                    b'u' => {
57	                        let cp = u32::from_str_radix(&s[i + 1..i + 5], 16).unwrap();
58	                        i += 4;
59	                        out.push(char::from_u32(cp).expect("BMP escape"));
60	                    }
61	                    other => panic!("unexpected JSON escape \\{}", other as char),
62	                }
63	                i += 1;
64	            }
65	            _ => {
66	                let c = s[i..].chars().next().unwrap();
67	                out.push(c);
68	                i += c.len_utf8();
69	            }
70	        }
71	    }
72	}
73	
74	/// Split a raw `{"html":"…","title":"…"}` body into (html, title), asserting
75	/// the exact serialization skeleton.
76	fn decode_envelope(raw: &str) -> (String, String) {
77	    let rest = raw.strip_prefix("{\"html\":\"").expect("envelope opens with html key");
78	    let (html, end) = decode_json_string(rest);
79	    let rest = rest[end..]
80	        .strip_prefix("\",\"title\":\"")
81	        .expect("title key follows html");
82	    let (title, end) = decode_json_string(rest);
83	    assert_eq!(&rest[end..], "\"}", "envelope closes after title");
84	    (html, title)
85	}
86	
87	// ---------------------------------------------------------------------------
88	// Skin inversion: postprocessed fragment -> logical lines -> headed blocks
89	// ---------------------------------------------------------------------------
90	
91	/// Invert the per-line postprocess: `<br/>\n`-terminated lines with leading
92	/// `&nbsp;` runs back to plain lines with leading spaces.
93	fn unpostprocess(html: &str) -> Vec<String> {
94	    assert!(html.ends_with("<br/>\n"), "postprocessed fragment ends with a break");
95	    let mut lines: Vec<&str> = html.split("<br/>\n").collect();
96	    assert_eq!(lines.pop(), Some(""), "trailing separator");
97	    lines
98	        .iter()
99	        .map(|line| {
100	            let mut rest = *line;
101	            let mut n = 0;
102	            while let Some(r) = rest.strip_prefix("&nbsp;") {
103	                rest = r;
104	                n += 1;
105	            }
106	            format!("{}{}", " ".repeat(n), rest)
107	        })
108	        .collect()
109	}
110	
111	const P_OPEN: &str = "<p class=\"monospace rules\">";
112	
113	/// Parse logical lines into (leading-blank-line?, [(heading, body-lines)]).
114	fn parse_blocks(lines: &[String]) -> (bool, Vec<(String, Vec<String>)>) {
115	    let mut i = 0;
116	    let leading_blank = lines.first().is_some_and(|l| l.is_empty());
117	    if leading_blank {
118	        i = 1;
119	    }
120	    let mut blocks = Vec::new();
121	    while i < lines.len() {
122	        let heading = lines[i]
123	            .strip_prefix("<h2>")
124	            .and_then(|h| h.strip_suffix("</h2>"))
125	            .unwrap_or_else(|| panic!("expected heading line, got {:?}", lines[i]));
126	        i += 1;
127	        let first = lines[i]
128	            .strip_prefix(P_OPEN)
129	            .unwrap_or_else(|| panic!("expected paragraph open, got {:?}", lines[i]));
130	        let mut body = Vec::new();
131	        let mut cur = first.to_string();
132	        loop {
133	            if let Some(stripped) = cur.strip_suffix("</p>") {
134	                if !(stripped.is_empty() && body.is_empty()) {
135	                    body.push(stripped.to_string());
136	                }
137	                i += 1;
138	                break;
139	            }
140	            body.push(cur);
141	            i += 1;
142	            cur = lines[i].clone();
143	        }
144	        blocks.push((heading.to_string(), body));
145	    }
146	    (leading_blank, blocks)
147	}
148	
149	fn content(body: Vec<String>) -> Content {
150	    Content { lines: body }
151	}
152	
153	fn block(heading: &str, body: Vec<String>, when_empty: EmptyRender) -> HeadedBlock {
154	    HeadedBlock {
155	        heading: heading.into(),
156	        body: content(body),
157	        when_empty,
158	    }
159	}
160	
161	// ---------------------------------------------------------------------------
162	// Per-family reconstruction
163	// ---------------------------------------------------------------------------
164	
165	fn rebuild_message(html: &str, title: &str) -> ContentPane {
166	    assert_eq!(title, "Message theory");
167	    let (leading_blank, mut blocks) = parse_blocks(&unpostprocess(html));
168	    assert!(!leading_blank, "message pane has no leading blank");
169	    assert_eq!(blocks.len(), 3, "message pane emits exactly three sections");
170	    let heads: Vec<&str> = blocks.iter().map(|(h, _)| h.as_str()).collect();
171	    assert_eq!(
172	        heads,
173	        ["Signature", "Construction Rules", "Deconstruction Rules"]
174	    );
175	    ContentPane {
176	        title: title.into(),
177	        blocks: blocks
178	            .drain(..)
179	            .map(|(h, b)| block(&h, b, EmptyRender::Keep))
180	            .collect(),
181	    }
182	}
183	
184	fn rebuild_rules(html: &str, title: &str) -> ContentPane {
185	    assert_eq!(title, "Multiset rewriting rules and restrictions");
186	    let (leading_blank, parsed) = parse_blocks(&unpostprocess(html));
187	    let mut iter = parsed.into_iter().peekable();
188	
189	    // Macros slot: a real block, or the leading blank line when absent [L03].
190	    let macros_body = if iter.peek().is_some_and(|(h, _)| h == "Macros") {
191	        assert!(!leading_blank);
192	        iter.next().unwrap().1
193	    } else {
194	        assert!(leading_blank, "no macros block implies the blank slot");
195	        Vec::new()
196	    };
197	    let mut blocks = vec![block("Macros", macros_body, EmptyRender::BlankLine)];
198	
199	    let (h, b) = iter.next().expect("injective-facts section");
200	    assert_eq!(h, "Fact Symbols with Injective Instances");
201	    blocks.push(block(&h, b, EmptyRender::Keep));
202	
203	    let (h, b) = iter.next().expect("MSR section");
204	    assert_eq!(h, "Multiset Rewriting Rules");
205	    blocks.push(block(&h, b, EmptyRender::Keep));
206	
207	    // Restrictions: present, or omitted without residue [S10][S11].
208	    let restrictions = match iter.next() {
209	        Some((h, b)) => {
210	            assert_eq!(h, "Restrictions of the Set of Traces");
211	            b
212	        }
213	        None => Vec::new(),
214	    };
215	    blocks.push(block(
216	        "Restrictions of the Set of Traces",
217	        restrictions,
218	        EmptyRender::Omit,
219	    ));
220	    assert!(iter.next().is_none(), "no further sections");
221	    ContentPane {
222	        title: title.into(),
223	        blocks,
224	    }
225	}
226	
227	fn rebuild_tactic(html: &str, title: &str) -> ContentPane {
228	    assert_eq!(title, "Tactics");
229	    let (leading_blank, mut blocks) = parse_blocks(&unpostprocess(html));
230	    assert!(!leading_blank);
231	    assert_eq!(blocks.len(), 1);
232	    let (h, b) = blocks.pop().unwrap();
233	    assert_eq!(h, "Tactic(s)");
234	    ContentPane {
235	        title: title.into(),
236	        blocks: vec![block(&h, b, EmptyRender::Keep)],
237	    }
238	}
239	
240	/// Reverse of `escape_text` for the env-line fields (strict).
241	fn unescape_entities(s: &str) -> String {
242	    let mut out = String::with_capacity(s.len());
243	    let mut rest = s;
244	    while let Some(i) = rest.find('&') {
245	        out.push_str(&rest[..i]);
246	        rest = &rest[i..];
247	        let (c, len) = if rest.starts_with("&amp;") {
248	            ('&', 5)
249	        } else if rest.starts_with("&lt;") {
250	            ('<', 4)
251	        } else if rest.starts_with("&gt;") {
252	            ('>', 4)
253	        } else if rest.starts_with("&quot;") {
254	            ('"', 6)
255	        } else if rest.starts_with("&#39;") {
256	            ('\'', 5)
257	        } else {
258	            panic!("unknown entity at {:?}", &rest[..rest.len().min(8)]);
259	        };
260	        out.push(c);
261	        rest = &rest[len..];
262	    }
263	    out.push_str(rest);
264	    out
265	}
266	
267	fn rebuild_help(html: &str, title: &str) -> HelpPane {
268	    let static_at = html.find("<div id=\"help\">").expect("static help block");
269	    assert_eq!(&html[static_at..], HELP_STATIC_HTML, "invariant static block");
270	    let env = html[..static_at]
271	        .strip_prefix("<p>Theory: ")
272	        .and_then(|e| e.strip_suffix("</p>"))
273	        .expect("env line shape");
274	    let (pre, banner) = match env.find("<div class=\"wf-warning\"") {
275	        Some(i) => (&env[..i], &env[i..]),
276	        None => (env, ""),
277	    };
278	    let pre = pre.strip_suffix(") ").expect("env line closes with `) `");
279	    let (name, rest) = pre.split_once(" (Loaded at ").expect("Loaded-at marker");
280	    let (time, origin) = rest.split_once(" from ").expect("from marker");
281	    let name = unescape_entities(name);
282	    assert_eq!(title, format!("Theory: {name}"));
283	    HelpPane {
284	        theory_name: name,
285	        load_time: unescape_entities(time),
286	        origin: unescape_entities(origin),
287	        wf_banner_html: banner.into(),
288	    }
289	}
290	
291	fn replay(family: &str, raw: &str) -> String {
292	    let (html, title) = decode_envelope(raw);
293	    match family {
294	        "message" => render_content_pane(&rebuild_message(&html, &title)),
295	        "rules" => render_content_pane(&rebuild_rules(&html, &title)),
296	        "tactic" => render_content_pane(&rebuild_tactic(&html, &title)),
297	        "help" => render_help_pane(&rebuild_help(&html, &title)),
298	        other => panic!("unknown family {other}"),
299	    }
300	}
