302	// ---------------------------------------------------------------------------
303	// The sweeps
304	// ---------------------------------------------------------------------------
305	
306	/// All 81 manifests x 4 center fragments: slice, re-render, byte-compare the
307	/// whole response body (envelope included).
308	#[test]
309	fn corpus_sweep_all_manifests() {
310	    let dir = workspace_path("../r1_raw");
311	    let mut count = 0;
312	    let mut per_family = [0usize; 4];
313	    let mut entries: Vec<_> = fs::read_dir(&dir)
314	        .expect("workspace/r1_raw materialized (tools/extract_r1_raw.py)")
315	        .map(|e| e.unwrap().path())
316	        .filter(|p| p.extension().is_some_and(|e| e == "raw"))
317	        .collect();
318	    entries.sort();
319	    for path in entries {
320	        let stem = path.file_stem().unwrap().to_str().unwrap();
321	        let family = stem.rsplit("__main_").next().unwrap();
322	        let raw = fs::read_to_string(&path).unwrap();
323	        let rendered = replay(family, &raw);
324	        assert_eq!(rendered, raw, "byte mismatch replaying {stem}");
325	        per_family[["message", "rules", "tactic", "help"]
326	            .iter()
327	            .position(|f| *f == family)
328	            .unwrap()] += 1;
329	        count += 1;
330	    }
331	    assert_eq!(count, 324, "81 manifests x 4 fragments");
332	    assert_eq!(per_family, [81; 4]);
333	}
