335	/// Live-probe replays (workspace/r1_live/, raw bodies captured from the
336	/// oracle server on theories NOT in the crawl corpus): the own-authored
337	/// metachar-filename EscProbe theory [L06] and the macros-bearing
338	/// MacroGlobalVarNSPK3 [L03] — the only observed macros-present rules pane.
339	#[test]
340	fn live_probe_replays() {
341	    let dir = workspace_path("../r1_live");
342	    let mut count = 0;
343	    let mut entries: Vec<_> = fs::read_dir(&dir)
344	        .expect("workspace/r1_live materialized (QUERIES.log [L03][L06][L07])")
345	        .map(|e| e.unwrap().path())
346	        .filter(|p| p.extension().is_some_and(|e| e == "raw"))
347	        .collect();
348	    entries.sort();
349	    for path in entries {
350	        let stem = path.file_stem().unwrap().to_str().unwrap();
351	        let family = stem.rsplit("__main_").next().unwrap();
352	        let raw = fs::read_to_string(&path).unwrap();
