359	/// The curated round-1 byte targets (producers/round1/targets/): decoded
360	/// fragment + title files; re-render and byte-compare fragment and title.
361	#[test]
362	fn round1_materialized_targets() {
363	    let dir = workspace_path("../../round1/targets");
364	    let mut count = 0;
365	    let mut entries: Vec<_> = fs::read_dir(&dir)
366	        .expect("round1/targets materialized")
367	        .map(|e| e.unwrap().path())
368	        .filter(|p| p.extension().is_some_and(|e| e == "html"))
369	        .collect();
370	    entries.sort();
371	    for path in entries {
372	        let stem = path.file_stem().unwrap().to_str().unwrap();
373	        let family = stem.rsplit("_main_").next().unwrap();
374	        let html = fs::read_to_string(&path).unwrap();
375	        let title = fs::read_to_string(path.with_extension("title")).unwrap();
376	        let rebuilt_envelope = match family {
377	            "message" => render_content_pane(&rebuild_message(&html, &title)),
378	            "rules" => render_content_pane(&rebuild_rules(&html, &title)),
379	            "tactic" => render_content_pane(&rebuild_tactic(&html, &title)),
380	            "help" => render_help_pane(&rebuild_help(&html, &title)),
381	            other => panic!("unknown family {other}"),
382	        };
383	        let (out_html, out_title) = decode_envelope(&rebuilt_envelope);
384	        assert_eq!(out_html, html, "fragment byte mismatch for {stem}");
385	        assert_eq!(out_title, title, "title mismatch for {stem}");
386	        count += 1;
387	    }
388	    assert_eq!(count, 44, "11 curated labels x 4 fragments");
389	}
