1	//! R3 — trace-formula rendering (shared by restrictions and lemma statements).
2	//!
3	//! Every glyph and layout decision is oracle-pinned (see workspace/BEHAVIOR.md
4	//! "Formula rendering" for probe provenance). Shape summary:
5	//!
6	//! * glyphs: `∀ ∃ ⇒ ∧ ∨ ¬ ⇔ ⊤ ⊥`, atoms `@ < = ⊏ last(..)`;
7	//! * EVERY operand of a binary connective and every `¬` argument is
8	//!   parenthesized; quantifier bodies and the top level are bare; chains
9	//!   keep their source association (probe:q_p2);
10	//! * binary connective = `sep [lhs <+> glyph, rhs]` — the glyph attaches to
11	//!   the lhs' last line, the rhs drops to the group origin;
12	//! * quantifier = `sep [`∀ `<>fsep binders<>`.`, nest 1 body]` — binders
13	//!   fill-wrap aligned after the glyph-plus-space, the body indents one
14	//!   column past the glyph (probe:q_l2);
15	//! * atoms reuse the R2 fact and R1 term docs: `Fact( … ) @ tp` is an hsep
16	//!   (the `@ tp` never drops alone — probe:q_l5), `l = r` / `l < r` /
17	//!   `l ⊏ r` are `sep [lhs <+> glyph, rhs]` (probe:q_l4), `last(tp)` has no
18	//!   interior spaces (probe:q_at1).
19	
20	use crate::ast::{Atom, Formula, VarSpec};
21	use crate::doc::{
22	    beside_op, beside_space, char, fsep, hsep, nest, render_with, sep, text, Doc,
23	};
24	use crate::rule::fact_doc;
25	use crate::term::{self, RIBBON, WIDTH};
26	
27	/// Render one formula at the echo's layout parameters, starting at column 0
28	/// (top-level position — no enclosing parentheses).
29	pub fn render(f: &Formula) -> String {
30	    render_with(WIDTH, RIBBON, &doc(f))
31	}
32	
33	/// The formula's `Doc` in BARE position (top level or quantifier body).
34	pub(crate) fn doc(f: &Formula) -> Doc {
35	    match f {
36	        Formula::True => text("\u{22a4}"),
37	        Formula::False => text("\u{22a5}"),
38	        Formula::Atom(a) => atom_doc(a),
39	        Formula::Not(g) => beside_op(text("\u{ac}"), parens(doc(g))),
40	        Formula::And(l, r) => connective_doc(l, "\u{2227}", r),
41	        Formula::Or(l, r) => connective_doc(l, "\u{2228}", r),
42	        Formula::Implies(l, r) => connective_doc(l, "\u{21d2}", r),
43	        Formula::Iff(l, r) => connective_doc(l, "\u{21d4}", r),
44	        Formula::Forall(vs, b) => quantifier_doc("\u{2200}", vs, b),
45	        Formula::Exists(vs, b) => quantifier_doc("\u{2203}", vs, b),
46	    }
47	}
48	
49	fn parens(d: Doc) -> Doc {
50	    beside_op(beside_op(char('('), d), char(')'))
51	}
52	
53	/// `(lhs) <glyph> (rhs)` — both operands parenthesized whatever they are
54	/// (probe:q_p2); on overflow the glyph stays on the lhs' last line and the
55	/// rhs drops to the group origin (targets NSLPK3/Cronto).
56	fn connective_doc(l: &Formula, glyph: &str, r: &Formula) -> Doc {
57	    sep(vec![
58	        beside_space(parens(doc(l)), text(glyph)),
59	        parens(doc(r)),
60	    ])
61	}
62	
63	/// `∀ v1 v2 #i. body` — binders fill-wrap aligned after `∀ ` with the `.`
64	/// attached to the last one; the body sits beside on one line or drops to
65	/// (quantifier origin + 1) (probe:q_l2 bw1/bw2).
66	fn quantifier_doc(glyph: &str, vs: &[VarSpec], body: &Formula) -> Doc {
67	    let binders = fsep(vs.iter().map(|v| text(&term::var_str(v))).collect());
68	    let head = beside_op(
69	        beside_op(text(&format!("{glyph} ")), binders),
70	        char('.'),
71	    );
72	    sep(vec![head, nest(1, &doc(body))])
73	}
74	
75	fn atom_doc(a: &Atom) -> Doc {
76	    match a {
77	        Atom::Eq(l, r) => relation_doc(l, "=", r),
78	        Atom::Less(l, r) => relation_doc(l, "<", r),
79	        // UNOBSERVABLE placeholder (BEHAVIOR.md): rendered like Less; not
80	        // oracle-pinned.
81	        Atom::LessMset(l, r) => relation_doc(l, "<", r),
82	        Atom::Subterm(l, r) => relation_doc(l, "\u{228f}", r),
83	        Atom::Action(f, tp) => hsep(vec![fact_doc(f), char('@'), term::doc(tp)]),
84	        Atom::Last(tp) => beside_op(beside_op(text("last("), term::doc(tp)), char(')')),
85	        // UNOBSERVABLE placeholder (BEHAVIOR.md): predicates are expanded
86	        // upstream of the echo; rendered as a bare fact, not oracle-pinned.
87	        Atom::Pred(f) => fact_doc(f),
88	    }
89	}
90	
91	/// `lhs <glyph> rhs` for `=` / `<` / `⊏`: glyph attached to the lhs' last
92	/// line, rhs drops to the atom origin on overflow (probe:q_l4).
93	fn relation_doc(l: &crate::ast::Term, glyph: &str, r: &crate::ast::Term) -> Doc {
94	    sep(vec![
95	        beside_space(term::doc(l), text(glyph)),
96	        term::doc(r),
97	    ])
98	}
99	
100	/// Safety classification for the restriction wrapper's `// safety formula`
101	/// line: a formula is safety iff its negation-normal form contains NO
102	/// existential quantifier — msg-sort or temporal alike (probes q_s1/q_s2:
103	/// ∃ in positive polarity anywhere, including a `¬∃` antecedent that
104	/// double-negates back, defeats it; `¬∃` in conclusion and top-level `¬∃`
105	/// remain safety).
106	pub(crate) fn is_safety(f: &Formula) -> bool {
107	    !has_existential_in_nnf(f, false)
108	}
109	
110	/// Does `f` contain a quantifier that becomes existential in NNF, given the
111	/// number of enclosing negations (`negated`)?
112	fn has_existential_in_nnf(f: &Formula, negated: bool) -> bool {
113	    match f {
114	        Formula::True | Formula::False | Formula::Atom(_) => false,
115	        Formula::Not(g) => has_existential_in_nnf(g, !negated),
116	        Formula::And(l, r) | Formula::Or(l, r) => {
117	            has_existential_in_nnf(l, negated) || has_existential_in_nnf(r, negated)
118	        }
119	        Formula::Implies(l, r) => {
120	            has_existential_in_nnf(l, !negated) || has_existential_in_nnf(r, negated)
121	        }
122	        // ⇔ expands to implications in both directions, so each side occurs
123	        // in both polarities. No safety-relevant ⇔ was observable (see
124	        // BEHAVIOR.md); this is the NNF-consistent reading.
125	        Formula::Iff(l, r) => {
126	            has_existential_in_nnf(l, false)
127	                || has_existential_in_nnf(l, true)
128	                || has_existential_in_nnf(r, false)
129	                || has_existential_in_nnf(r, true)
130	        }
131	        Formula::Forall(_, b) => negated || has_existential_in_nnf(b, negated),
132	        Formula::Exists(_, b) => !negated || has_existential_in_nnf(b, negated),
133	    }
134	}
135

1	//! R2 — rule rendering: the whole rule block, byte-identical to the echo.
2	//!
3	//! Every layout decision is oracle-pinned (see workspace/BEHAVIOR.md "Rule
4	//! blocks" for probe provenance). Shape summary:
5	//!
6	//! ```text
7	//! rule (modulo E) Name[color=#abcdef, no_derivcheck, issapicrule,
8	//!                      role='r']:
9	//!    [ Prem( x ), !Persistent( y )[+, no_precomp] ]
10	//!   --[ Act( x ) ]->
11	//!    [ Concl( x ) ]
12	//!
13	//!   // loop breakers: [0,1]
14	//!   /* has exactly the trivial AC variant */
15	//! ```
16	//!
17	//! * body = `nest 3 (sep [prems, nest (-1) arrow, concls])` — one line when
18	//!   it fits, otherwise premises/conclusions at indent 3 and the arrow row at
19	//!   indent 2;
20	//! * each bracket group = `sep ["[", fsep facts, "]"]` (`[ ]` when empty);
21	//!   the empty-action arrow is the literal `-->`;
22	//! * a fact = `sep [name<>"(" <+> fsep args, ")"]` (`Name( )` when nullary)
23	//!   with the annotation suffix attached after the `)`;
24	//! * the trailing comment is either the trivial-variant one-liner or the
25	//!   `/* rule (modulo AC) … variants (modulo AC) … */` block with numbered
26	//!   substitution groups: number right-aligned to the widest index, each
27	//!   substitution `lhs $$ nest 6 ("= " <> rhs)` — the HughesPJ overlap pads
28	//!   a short lhs to column 6 and pushes `= rhs` to its own line otherwise.
29	
30	use crate::ast::{AcVariants, Fact, FactAnnotation, Rule, RuleAttr, Term};
31	use crate::doc::{
32	    above_op, above_plus, beside_op, beside_space, char, fsep, nest, punctuate,
33	    render_with, sep, text, vcat, Doc,
34	};
35	use crate::term::{self, RIBBON, WIDTH};
36	
37	/// One fact: `Name( arg, … )`, persistent prefixed with `!`, annotations
38	/// attached after the closing paren.
39	pub fn render_fact(f: &Fact) -> String {
40	    render_with(WIDTH, RIBBON, &fact_doc(f))
41	}
42	
43	/// One whole rule block: header, body, blank line, loop-breaker annotation,
44	/// and the AC-variants comment (`None` → the trivial-variant one-liner).
45	pub fn render(rule: &Rule, variants: Option<&AcVariants>) -> String {
46	    render_with(WIDTH, RIBBON, &block_doc(rule, variants))
47	}
48	
49	fn block_doc(rule: &Rule, variants: Option<&AcVariants>) -> Doc {
50	    let mut d = core_doc(rule);
51	    // `$+$` below the blank line: `$$` overlap would otherwise pull the
52	    // nested comment line up onto it.
53	    d = above_plus(d, text(""));
54	    if let Some(lb) = breaker_doc(&rule.loop_breakers) {
55	        d = above_plus(d, nest(2, &lb));
56	    }
57	    above_plus(d, nest(2, &comment_doc(variants)))
58	}
59	
60	/// Header + body (shared by the toplevel block and the AC rule re-rendered
61	/// inside the variants comment).
62	fn core_doc(rule: &Rule) -> Doc {
63	    above_op(header_doc(rule), nest(3, &body_doc(rule)))
64	}
65	
66	// ── header ──────────────────────────────────────────────────────────────────
67	
68	/// `rule (modulo E) Name:`, with the rendered attribute list in `[…]` before
69	/// the colon; attributes fill-wrap aligned after the `[`
70	/// (target:issue713, probe:p_rattr).
71	fn header_doc(rule: &Rule) -> Doc {
72	    let mut head = String::from("rule ");
73	    if let Some(m) = &rule.modulo {
74	        head.push_str(&format!("(modulo {m}) "));
75	    }
76	    head.push_str(&rule.name);
77	    let attrs = attr_items(&rule.attributes);
78	    if attrs.is_empty() {
79	        text(&format!("{head}:"))
80	    } else {
81	        beside_op(
82	            beside_op(
83	                text(&format!("{head}[")),
84	                fsep(punctuate(
85	                    &char(','),
86	                    attrs.iter().map(|a| text(a)).collect(),
87	                )),
88	            ),
89	            text("]:"),
90	        )
91	    }
92	}
93	
94	/// Canonical attribute list: color, process, no_derivcheck, issapicrule, role
95	/// — the last color/process/role declaration wins; external attributes are
96	/// dropped (probe:p_rattr, target:issue713; target:ct pins the SAPIC
97	/// `process` attribute).
98	///
99	/// The SAPIC `process="…"` attribute (target:ct, probe:p_process) renders
100	/// DOUBLE-quoted (unlike `role='…'`), between `color` and `no_derivcheck`, and
101	/// carries the process snippet VERBATIM: no escaping is applied and none is
102	/// observable (its text uses single-quoted string constants — `'proofOfID'` —
103	/// so no `"`/`\` ever appears; spaces, commas, `<>`, `()`, `;` all sit inside
104	/// the quotes as one unbreakable text token). Absent when the rule is not
105	/// SAPIC-generated (no `RuleAttr::Process`).
106	fn attr_items(attrs: &[RuleAttr]) -> Vec<String> {
107	    let mut color = None;
108	    let mut process = None;
109	    let mut no_derivcheck = false;
110	    let mut issapicrule = false;
111	    let mut role = None;
112	    for a in attrs {
113	        match a {
114	            RuleAttr::Color(c) => color = Some(c.clone()),
115	            RuleAttr::Process(p) => process = Some(p.clone()),
116	            RuleAttr::NoDerivCheck => no_derivcheck = true,
117	            RuleAttr::IsSapicRule => issapicrule = true,
118	            RuleAttr::Role(r) => role = Some(r.clone()),
119	            RuleAttr::External(..) => {}
120	        }
121	    }
122	    let mut items = Vec::new();
123	    if let Some(c) = color {
124	        items.push(format!("color=#{c}"));
125	    }
126	    if let Some(p) = process {
127	        items.push(format!("process=\"{p}\""));
128	    }
129	    if no_derivcheck {
130	        items.push("no_derivcheck".into());
131	    }
132	    if issapicrule {
133	        items.push("issapicrule".into());
