190	/// Suspend a document computation (a thunk). The closure runs at most once.
191	fn lazy<F: FnOnce() -> Doc + 'static>(f: F) -> Doc {
192	    Lazy(Rc::new(LazyDoc(RefCell::new(LazyState::Pending(Some(
193	        Box::new(f),
194	    ))))))
195	}
