594	/// `hsep` — list version of `<+>`.
595	pub fn hsep(ds: Vec<Doc>) -> Doc {
596	    let folded = ds
597	        .into_iter()
598	        .rev()
599	        .fold(Empty, |q, p| Beside(rc(p), true, rc(q)));
600	    reduce_horiz(&folded).1
601	}
