617	/// `punctuate p [d1,…,dn] = [d1<>p, …, d(n-1)<>p, dn]`.
618	pub fn punctuate(p: &Doc, ds: Vec<Doc>) -> Vec<Doc> {
619	    let n = ds.len();
620	    ds.into_iter()
621	        .enumerate()
622	        .map(|(i, d)| {
623	            if i + 1 < n {
624	                beside_op(d, p.clone())
625	            } else {
626	                d
627	            }
628	        })
629	        .collect()
630	}
