727	fn fill(g: bool, ds: Vec<Doc>) -> Doc {
728	    if ds.is_empty() {
729	        return Empty;
730	    }
731	    let mut it = ds.into_iter();
732	    let p = it.next().unwrap();
733	    let ys: Vec<Doc> = it.collect();
734	    fill1(g, &reduce_doc(&p), 0, &ys)
735	}
