792	fn fill_nbe(g: bool, k: isize, y: &Doc, ys: &[Doc]) -> Doc {
793	    let k1 = if g { k - 1 } else { k };
794	    let y_one = elide_nest(&one_liner(&reduce_doc(y)));
795	    let left = nil_beside(g, &fill1(g, &y_one, k1, ys));
796	    let (y2, ys2) = (y.clone(), ys.to_vec());
797	    let right = lazy(move || {
798	        let mut rest = vec![y2];
799	        rest.extend(ys2);
800	        nil_above_nest(false, k, &fill(g, rest))
801	    });
802	    mk_union(left, right)
803	}
