837	/// `best w r doc` — resolve unions to a single layout for line width `w`,
838	/// ribbon width `r`. Mirrors the Haskell `best`/`nicest1` including its
839	/// laziness: the resolved document's tails are thunks, so `fits` (which only
840	/// inspects a candidate's *first line*) never forces a branch beyond that
841	/// line, and the right branch of a union is only resolved when the left's
842	/// first line does not fit.
843	fn best(w: isize, r: isize, d: &Doc) -> Doc {
844	    get(w, r, d)
845	}
846	
847	fn get(w: isize, r: isize, d: &Doc) -> Doc {
848	    let df = force(d);
849	    match &df {
850	        Empty => Empty,
851	        NoDoc => NoDoc,
852	        NilAbove(p) => {
853	            let p = p.clone();
854	            nil_above_(rc(lazy(move || get(w, r, &p))))
855	        }
856	        TextBeside(s, l, p) => {
857	            let (li, p) = (*l as isize, p.clone());
858	            text_beside_(s.clone(), *l, rc(lazy(move || get1(w, r, li, &p))))
859	        }
860	        Nest(k, p) => {
861	            let (k, p) = (*k, p.clone());
862	            nest_(k, rc(lazy(move || get(w - k, r, &p))))
863	        }
864	        Union(p, q) => nicest(w, r, p, q),
865	        Above(..) => panic!("best get Above"),
866	        Beside(..) => panic!("best get Beside"),
867	        Lazy(_) => unreachable!("get: forced doc"),
868	    }
869	}
