871	fn get1(w: isize, r: isize, sl: isize, d: &Doc) -> Doc {
872	    let df = force(d);
873	    match &df {
874	        Empty => Empty,
875	        NoDoc => NoDoc,
876	        NilAbove(p) => {
877	            let p = p.clone();
878	            nil_above_(rc(lazy(move || get(w - sl, r, &p))))
879	        }
880	        TextBeside(s, l, p) => {
881	            let (li, p) = (*l as isize, p.clone());
882	            text_beside_(
883	                s.clone(),
884	                *l,
885	                rc(lazy(move || get1(w, r, sl + li, &p))),
886	            )
887	        }
888	        Nest(_, p) => get1(w, r, sl, p),
889	        Union(p, q) => nicest1(w, r, sl, p, q),
890	        Above(..) => panic!("best get1 Above"),
891	        Beside(..) => panic!("best get1 Beside"),
892	        Lazy(_) => unreachable!("get1: forced doc"),
893	    }
894	}
