942	/// Banker's-rounding of `line_len / ribbons` to match Haskell `round`.
943	fn round_ribbon(line_len: isize, ribbons: f64) -> isize {
944	    let v = line_len as f64 / ribbons;
945	    let floor = v.floor();
946	    let diff = v - floor;
947	    let rounded = if (diff - 0.5).abs() < 1e-9 {
948	        // round half to even
949	        let f = floor as i64;
950	        if f % 2 == 0 {
951	            f
952	        } else {
953	            f + 1
954	        }
955	    } else {
956	        v.round() as i64
957	    };
958	    rounded as isize
959	}
