// TEMPORARY width-probe (deleted after use). Reproduces a captured web-mode
// `functions:` fill + `equations:` block at candidate (width, ribbon) pairs.
use pretty_clean::doc::{beside_op, char, fsep, nest, punctuate, render_with, sep, text, Doc};

fn functions_doc(items: &[&str]) -> Doc {
    beside_op(
        text("functions: "),
        fsep(punctuate(&char(','), items.iter().map(|s| text(s)).collect())),
    )
}

// equations: sep(header : map (nest 4) (punctuate ',' eqDocs))
fn equations_doc(eqs: &[&str]) -> Doc {
    let mut items = vec![text("equations:")];
    for d in punctuate(&char(','), eqs.iter().map(|s| text(s)).collect()) {
        items.push(nest(4, &d));
    }
    sep(items)
}

