use pretty_clean::doc::{char, fsep, punctuate, render_with, text, Doc};

fn fill_two(w1: usize, w2: usize) -> Doc {
    let a = "a".repeat(w1);
    let b = "b".repeat(w2);
    fsep(punctuate(&char(','), vec![text(&a), text(&b)]))
}

#[test]
fn probe_ribbon_boundary() {
    // item1 width 60 -> "aaa...," ends at col 61 (60 + comma). fill space -> b
    // starts at 62. b of width W ends at col 61 + 1 + W.
    // We vary W so the b-end lands on 66,67,68,69 and observe wrap per ribbon.
    for w2 in [4usize, 5, 6, 7] {
        // b-end column if kept on line 1 = 60 + 1(comma) + 1(space) + w2 = 62 + w2
        let end_col = 62 + w2;
        for r in [65isize, 66, 67, 68] {
            let out = render_with(100, r, &fill_two(60, w2));
            let wrapped = out.contains('\n');
            println!(
                "w2={w2} (b would end at col {end_col})  ribbon={r}  wrapped={wrapped}"
            );
        }
        println!("---");
    }
}

