70	        d = above_op(d, nest(2, &text("// safety formula")));
71	    }
72	    // One blank line, then the expanded-formula comment at col 2. The STATEMENT
73	    // renders `r.formula` (macros unexpanded); the comment renders
74	    // `r.expanded` (macro/predicate-expanded — target:MacroInLemmasAndRestrictions
75	    // shows the two differing, e.g. statement `A( m(m3(x)) )` vs expanded
76	    // `A( x )`). Without macros the two are equal, so this reproduces the
77	    // earlier same-formula-twice observation (probes q_w1/q_pred1).
78	    d = above_plus(d, text(""));
79	    let comment = above_op(
80	        above_op(
81	            above_op(text("/*"), text("expanded formula:")),
82	            quoted_formula(&r.expanded),
83	        ),
84	        text("*/"),
85	    );
86	    above_plus(d, nest(2, &comment))
87	}
88	
89	// ── lemmas ──────────────────────────────────────────────────────────────────
90	
91	fn lemma_doc(l: &Lemma, guarded: Option<&Guarded>) -> Doc {
92	    let mut d = above_op(header_doc(l), nest(2, &statement_doc(l)));
93	    if let Some(g) = guarded {
94	        d = above_op(d, guarded_comment_doc(l.trace_quantifier, g));
95	    }
96	    let tail = match &l.proof {
97	        None => text("by sorry"),
98	        Some(p) => verbatim_doc(p),
99	    };
100	    above_op(d, tail)
101	}
102	
103	/// `lemma Name:` or `lemma Name [attrs]:` — a space before the `[`, the
104	/// attribute list fill-wrapped aligned after it with `]:` attached to the
105	/// last item (targets 5G_AKA sqn_ue_nodecrease / sqn_ue_unique); attributes
106	/// keep source order and duplicates (probe:q_la1).
107	fn header_doc(l: &Lemma) -> Doc {
108	    if l.attributes.is_empty() {
109	        return text(&format!("lemma {}:", l.name));
110	    }
111	    let items: Vec<Doc> = l.attributes.iter().map(|a| text(&attr_str(a))).collect();
112	    beside_op(
113	        beside_op(
114	            text(&format!("lemma {} [", l.name)),
115	            fsep(punctuate(&crate::doc::char(','), items)),
116	        ),
117	        text("]:"),
118	    )
119	}
120	
121	fn attr_str(a: &LemmaAttr) -> String {
122	    match a {
123	        LemmaAttr::Sources => "sources".into(),
124	        LemmaAttr::Reuse => "reuse".into(),
125	        LemmaAttr::UseInduction => "use_induction".into(),
126	        LemmaAttr::HideLemma(n) => format!("hide_lemma={n}"),
127	        LemmaAttr::Heuristic(v) => format!("heuristic={v}"),
128	    }
129	}
130	
131	/// `all-traces "…"` / `exists-trace "…"` at nest 2 — one line when the whole
132	/// statement fits, otherwise the keyword alone with the quoted formula below
133	/// at the same column (probe:q_w1; target:Minimal_Loop one-line cases).
134	fn statement_doc(l: &Lemma) -> Doc {
135	    let kw = match l.trace_quantifier {
136	        TraceQuantifier::AllTraces => "all-traces",
137	        TraceQuantifier::ExistsTrace => "exists-trace",
138	    };
139	    sep(vec![text(kw), quoted_formula(&l.formula)])
140	}
141	
142	/// The guarded-formula comment at column 0. Header text keyed by the trace
143	/// quantifier; content is opaque pre-computed input (probe:q_w1). Failed
144	/// conversions get the alternate header with the error text indented 2
145	/// (probe:q_r1 vs. the transform's raw error spelling).
146	fn guarded_comment_doc(tq: TraceQuantifier, g: &Guarded) -> Doc {
147	    let body = match g {
148	        Guarded::Formula(content) => {
149	            let header = match tq {
150	                TraceQuantifier::AllTraces => {
151	                    "guarded formula characterizing all counter-examples:"
152	                }
153	                TraceQuantifier::ExistsTrace => {
154	                    "guarded formula characterizing all satisfying traces:"
155	                }
156	            };
157	            above_op(text(header), verbatim_doc(content))
158	        }
159	        Guarded::Failed(err) => {
160	            let indented: Vec<Doc> = err
161	                .lines()
162	                .map(|ln| {
163	                    if ln.is_empty() {
164	                        text("")
165	                    } else {
166	                        text(&format!("  {ln}"))
167	                    }
168	                })
169	                .collect();
170	            above_op(text("conversion to guarded formula failed:"), vcat(indented))
171	        }
172	    };
173	    above_op(above_op(text("/*"), body), text("*/"))
174	}
