253	        assert!(
254	            self.eat(tok),
255	            "expected {tok:?} at …{:?}",
256	            &self.rest()[..self.rest().len().min(70)]
257	        );
258	    }
259	    fn ident(&mut self) -> String {
260	        self.ws();
261	        let s: String = self
262	            .rest()
263	            .chars()
264	            .take_while(|c| c.is_ascii_alphanumeric() || *c == '_')
265	            .collect();
266	        assert!(
267	            !s.is_empty(),
268	            "expected ident at …{:?}",
269	            &self.rest()[..self.rest().len().min(50)]
270	        );
271	        self.pos += s.len();
272	        s
273	    }
274	    fn digits(&mut self) -> String {
275	        let s: String = self
276	            .rest()
277	            .chars()
278	            .take_while(|c| c.is_ascii_digit())
279	            .collect();
280	        self.pos += s.len();
281	        s
282	    }
283	    fn name_idx(&mut self) -> (String, u64) {
284	        let name = self.ident();
285	        if self.rest().starts_with('.')
286	            && self.s[self.pos + 1..]
287	                .chars()
288	                .next()
289	                .is_some_and(|c| c.is_ascii_digit())
290	        {
291	            self.pos += 1;
292	            let idx = self.digits().parse().unwrap();
293	            (name, idx)
294	        } else {
295	            (name, 0)
296	        }
297	    }
298	    fn quoted(&mut self) -> String {
299	        self.expect("'");
300	        let end = self.rest().find('\'').expect("unterminated quote");
301	        let s = self.rest()[..end].to_string();
302	        self.pos += end + 1;
303	        s
304	    }
305	
306	    // ── terms ──
307	    fn term(&mut self) -> Term {
308	        let mut t = self.atom();
309	        while self.starts("^") {
310	            self.pos += 1;
311	            let rhs = self.atom();
312	            t = Term::BinOp(BinOp::Exp, Box::new(t), Box::new(rhs));
313	        }
314	        t
315	    }
316	    fn sorted_var(&mut self, sort: SortHint) -> Term {
317	        let (name, idx) = self.name_idx();
318	        Term::Var(VarSpec { name, idx, sort, typ: None })
319	    }
320	    fn atom(&mut self) -> Term {
321	        self.ws();
322	        let c = self.rest().chars().next().expect("term expected");
323	        match c {
324	            '\'' => Term::PubLit(self.quoted()),
325	            '~' => {
326	                self.pos += 1;
327	                if self.rest().starts_with('\'') {
328	                    Term::FreshLit(self.quoted())
329	                } else {
330	                    self.sorted_var(SortHint::Fresh)
331	                }
332	            }
333	            '$' => {
334	                self.pos += 1;
335	                self.sorted_var(SortHint::Pub)
336	            }
337	            '#' => {
338	                self.pos += 1;
339	                self.sorted_var(SortHint::Node)
340	            }
341	            '%' => {
342	                self.pos += 1;
343	                if self.rest().chars().next().is_some_and(|c| c.is_ascii_digit()) {
344	                    Term::NatLit(self.digits())
345	                } else {
346	                    self.sorted_var(SortHint::Nat)
347	                }
348	            }
349	            '<' => {
350	                self.pos += 1;
351	                let mut elems = vec![self.term()];
352	                while self.eat(",") {
353	                    elems.push(self.term());
354	                }
355	                self.expect(">");
356	                Term::Pair(elems)
357	            }
358	            '(' => {
359	                self.pos += 1;
360	                let first = self.term();
361	                let op = if self.starts("++") {
362	                    BinOp::Union
363	                } else if self.starts("%+") {
364	                    BinOp::NatPlus
365	                } else if self.starts("\u{2295}") {
366	                    BinOp::Xor
367	                } else if self.starts("*") {
368	                    BinOp::Mult
369	                } else {
370	                    panic!("AC operator expected at …{:?}", &self.rest()[..self.rest().len().min(50)]);
371	                };
372	                let glyph = match op {
373	                    BinOp::Union => "++",
374	                    BinOp::NatPlus => "%+",
375	                    BinOp::Xor => "\u{2295}",
376	                    BinOp::Mult => "*",
377	                    BinOp::Exp => unreachable!(),
378	                };
379	                let mut t = first;
380	                while self.eat(glyph) {
381	                    let rhs = self.term();
382	                    t = Term::BinOp(op, Box::new(t), Box::new(rhs));
383	                }
384	                self.expect(")");
385	                t
386	            }
387	            _ => {
388	                let (name, idx) = self.name_idx();
389	                if self.rest().starts_with('(') {
390	                    self.pos += 1;
391	                    let mut args = vec![self.term()];
392	                    while self.eat(",") {
393	                        args.push(self.term());
394	                    }
395	                    self.expect(")");
396	                    Term::App(name, args)
397	                } else {
398	                    Term::Var(VarSpec { name, idx, sort: SortHint::Untagged, typ: None })
399	                }
400	            }
401	        }
402	    }
403	
404	    // ── facts (with rule-fact annotations) ──
405	    fn fact(&mut self) -> Fact {
406	        self.ws();
407	        let persistent = self.eat("!");
408	        let name = self.ident();
409	        self.expect("(");
410	        self.ws();
411	        let mut args = Vec::new();
412	        if !self.rest().starts_with(')') {
413	            args.push(self.term());
414	            while self.eat(",") {
415	                args.push(self.term());
416	            }
417	        }
418	        self.expect(")");
419	        let mut annotations = Vec::new();
420	        if self.rest().starts_with('[') {
421	            self.pos += 1;
422	            loop {
423	                self.ws();
424	                if self.eat("+") {
425	                    annotations.push(FactAnnotation::SolveFirst);
426	                } else if self.eat("-") {
427	                    annotations.push(FactAnnotation::SolveLast);
428	                } else if self.eat("no_precomp") {
429	                    annotations.push(FactAnnotation::NoSources);
430	                } else {
431	                    panic!("annotation expected");
432	                }
433	                if !self.eat(",") {
434	                    break;
435	                }
436	            }
437	            self.expect("]");
438	        }
439	        Fact { persistent, name, args, annotations }
440	    }
441	    fn fact_seq(&mut self, close: &str) -> Vec<Fact> {
442	        self.ws();
443	        let mut facts = Vec::new();
444	        if !self.starts(close) {
445	            facts.push(self.fact());
446	            while self.eat(",") {
447	                facts.push(self.fact());
448	            }
449	        }
450	        self.expect(close);
451	        facts
452	    }
