454	    // ── rules ──
455	    fn rule_core(&mut self) -> Rule {
456	        self.expect("rule");
457	        self.ws();
458	        let modulo = if self.eat("(modulo") {
459	            let m = self.ident();
460	            self.expect(")");
461	            Some(m)
462	        } else {
463	            None
464	        };
465	        self.ws();
466	        let name: String = self
467	            .rest()
468	            .chars()
469	            .take_while(|c| !matches!(c, '[' | ':') && !c.is_whitespace())
470	            .collect();
471	        self.pos += name.len();
472	        let mut attributes = Vec::new();
473	        if self.rest().starts_with('[') {
474	            self.pos += 1;
475	            loop {
476	                self.ws();
477	                if self.eat("color=#") {
478	                    let v: String = self.rest().chars().take_while(|c| c.is_ascii_alphanumeric()).collect();
479	                    self.pos += v.len();
480	                    attributes.push(RuleAttr::Color(v));
481	                } else if self.eat("process=\"") {
482	                    let end = self.rest().find('"').expect("unterminated process=");
483	                    attributes.push(RuleAttr::Process(self.rest()[..end].into()));
484	                    self.pos += end + 1;
485	                } else if self.eat("no_derivcheck") {
486	                    attributes.push(RuleAttr::NoDerivCheck);
487	                } else if self.eat("issapicrule") {
488	                    attributes.push(RuleAttr::IsSapicRule);
489	                } else if self.eat("role='") {
490	                    let end = self.rest().find('\'').unwrap();
491	                    attributes.push(RuleAttr::Role(self.rest()[..end].into()));
492	                    self.pos += end + 1;
493	                } else {
494	                    panic!("attribute expected at …{:?}", &self.rest()[..self.rest().len().min(50)]);
495	                }
496	                if !self.eat(",") {
497	                    break;
498	                }
499	            }
500	            self.expect("]");
501	        }
502	        self.expect(":");
503	        self.expect("[");
504	        let premises = self.fact_seq("]");
505	        self.ws();
506	        let actions = if self.eat("-->") {
507	            Vec::new()
508	        } else {
509	            self.expect("--[");
510	            self.fact_seq("]->")
511	        };
512	        self.expect("[");

512	        self.expect("[");
513	        let conclusions = self.fact_seq("]");
514	        Rule { name, modulo, attributes, premises, actions, conclusions, loop_breakers: vec![] }
515	    }
516	    fn breaker_line(&mut self) -> Vec<usize> {
517	        self.expect("//");
518	        self.ws();
519	        assert!(self.eat("loop breakers:") || self.eat("loop breaker:"));
520	        self.expect("[");
521	        let mut ids = vec![self.digits().parse().unwrap()];
522	        while self.eat(",") {
523	            self.ws();
524	            ids.push(self.digits().parse().unwrap());
525	        }
526	        self.expect("]");
527	        ids
528	    }
529	
530	    // ── formulas ──
531	    fn binder(&mut self) -> VarSpec {
532	        self.ws();
533	        let sort = if self.eat("~") {
534	            SortHint::Fresh
535	        } else if self.eat("$") {
536	            SortHint::Pub
537	        } else if self.eat("#") {
538	            SortHint::Node
539	        } else if self.eat("%") {
540	            SortHint::Nat
541	        } else {
542	            SortHint::Untagged
543	        };
544	        let (name, idx) = self.name_idx();
545	        VarSpec { name, idx, sort, typ: None }
546	    }
547	    fn quantifier(&mut self, glyph: &str) -> Formula {
548	        self.expect(glyph);
549	        let mut vs = Vec::new();
550	        loop {
551	            self.ws();
552	            if self.rest().starts_with('.') {
553	                self.pos += 1;
554	                break;
555	            }
556	            vs.push(self.binder());
557	        }
558	        let body = self.formula();
559	        if glyph == "\u{2200}" {
560	            Formula::Forall(vs, Box::new(body))
561	        } else {
562	            Formula::Exists(vs, Box::new(body))
563	        }
564	    }
565	    fn formula(&mut self) -> Formula {
566	        self.ws();
567	        if self.rest().starts_with('\u{2200}') {
568	            return self.quantifier("\u{2200}");
569	        }
570	        if self.rest().starts_with('\u{2203}') {
571	            return self.quantifier("\u{2203}");
572	        }
573	        let l = self.funit();
574	        self.ws();
575	        for (glyph, ctor) in [
576	            ("\u{2227}", Formula::And as fn(_, _) -> _),
577	            ("\u{2228}", Formula::Or as fn(_, _) -> _),
578	            ("\u{21d2}", Formula::Implies as fn(_, _) -> _),
579	            ("\u{21d4}", Formula::Iff as fn(_, _) -> _),
580	        ] {
581	            if self.eat(glyph) {
582	                let r = self.funit();
583	                return ctor(Box::new(l), Box::new(r));
584	            }
585	        }
586	        l
587	    }
588	    fn funit(&mut self) -> Formula {
589	        self.ws();
590	        if self.eat("\u{22a4}") {
591	            return Formula::True;
592	        }
593	        if self.eat("\u{22a5}") {
594	            return Formula::False;
595	        }
596	        if self.eat("\u{ac}") {
597	            self.expect("(");
598	            let f = self.formula();
599	            self.expect(")");
600	            return Formula::Not(Box::new(f));
601	        }
602	        if self.rest().starts_with('\u{2200}') {
603	            return self.quantifier("\u{2200}");
604	        }
605	        if self.rest().starts_with('\u{2203}') {
606	            return self.quantifier("\u{2203}");
607	        }
608	        if self.rest().starts_with('(') && !self.paren_is_term() {
609	            self.pos += 1;
610	            let f = self.formula();
611	            self.expect(")");
612	            return f;
613	        }
614	        self.formula_atom()
615	    }
616	    fn paren_is_term(&self) -> bool {
617	        let bytes = self.rest();
618	        let mut depth = 0usize;
619	        let mut it = bytes.char_indices();
620	        let close_end = loop {
621	            let Some((i, c)) = it.next() else { return false };
622	            match c {
623	                '(' => depth += 1,
624	                ')' => {
625	                    depth -= 1;
626	                    if depth == 0 {
627	                        break i + 1;
628	                    }
629	                }
630	                _ => {}
631	            }
632	        };
633	        let after = bytes[close_end..].trim_start();
634	        after.starts_with('=')
635	            || after.starts_with('<')
636	            || after.starts_with('\u{228f}')
637	            || after.starts_with('@')
638	    }
639	    fn formula_atom(&mut self) -> Formula {
640	        self.ws();
641	        if self.rest().starts_with("last(") {
642	            self.pos += "last(".len();
643	            let t = self.term();
644	            self.expect(")");
645	            return Formula::Atom(Atom::Last(t));
646	        }
647	        if self.rest().starts_with('!') {
648	            let f = self.fact();
649	            self.expect("@");
650	            let tp = self.term();
651	            return Formula::Atom(Atom::Action(f, tp));
652	        }
653	        // Nullary fact `Name( )` at atom position is an action fact.
654	        let save = self.pos;
655	        let mut is_nullary_fact = false;
656	        if self.rest().chars().next().is_some_and(|c| c.is_ascii_alphanumeric() || c == '_') {
657	            let _ = self.ident();
658	            if self.starts("(") {
659	                self.pos += 1;
660	                if self.starts(")") {
661	                    is_nullary_fact = true;
662	                }
663	            }
664	        }
665	        self.pos = save;
666	        if is_nullary_fact {
667	            let f = self.fact();
668	            self.expect("@");
669	            let tp = self.term();
670	            return Formula::Atom(Atom::Action(f, tp));
671	        }
672	        let t = self.term();
673	        self.ws();
674	        if self.eat("@") {
675	            let (name, args) = match t {
676	                Term::App(name, args) => (name, args),
677	                Term::Var(v) => {
678	                    assert_eq!(v.idx, 0, "action fact head with index");
679	                    (v.name, vec![])
680	                }
681	                other => panic!("action atom on non-fact term {other:?}"),
682	            };
683	            let tp = self.term();
684	            return Formula::Atom(Atom::Action(
685	                Fact { persistent: false, name, args, annotations: vec![] },
686	                tp,
687	            ));
688	        }
689	        if self.eat("=") {
690	            let r = self.term();
691	            return Formula::Atom(Atom::Eq(t, r));
692	        }
693	        if self.eat("\u{228f}") {
694	            let r = self.term();
695	            return Formula::Atom(Atom::Subterm(t, r));
696	        }
697	        if self.eat("<") {
698	            let r = self.term();
699	            return Formula::Atom(Atom::Less(t, r));
700	        }
701	        panic!("relation glyph expected at …{:?}", &self.rest()[..self.rest().len().min(50)]);
702	    }
703	    fn lemma_attrs(&mut self) -> Vec<LemmaAttr> {
704	        let mut attrs = Vec::new();
705	        loop {
706	            self.ws();
707	            if self.eat("sources") {
708	                attrs.push(LemmaAttr::Sources);
709	            } else if self.eat("reuse") {
710	                attrs.push(LemmaAttr::Reuse);
711	            } else if self.eat("use_induction") {
712	                attrs.push(LemmaAttr::UseInduction);
713	            } else if self.eat("hide_lemma=") {
714	                attrs.push(LemmaAttr::HideLemma(self.ident()));
715	            } else if self.eat("heuristic=") {
716	                let v: String = self.rest().chars().take_while(|c| *c != ',' && *c != ']').collect();
717	                self.pos += v.len();
718	                attrs.push(LemmaAttr::Heuristic(v));
719	            } else {
720	                panic!("lemma attribute expected at …{:?}", &self.rest()[..self.rest().len().min(50)]);
721	            }
722	            if !self.eat(",") {
723	                break;
724	            }
725	        }
726	        attrs
727	    }
728	}
