732	fn parse_rule_block(block: &str) -> (Rule, Option<AcVariants>) {
733	    let mut p = P::new(block);
734	    let mut r = p.rule_core();
735	    if p.starts("//") {
736	        r.loop_breakers = p.breaker_line();
737	    }
738	    p.expect("/*");
739	    if p.eat("has exactly the trivial AC variant") {
740	        p.expect("*/");
741	        return (r, None);
742	    }
743	    let mut ac = p.rule_core();
744	    let mut substitutions: Vec<Vec<(Term, Term)>> = Vec::new();
745	    if p.eat("variants (modulo AC)") {
746	        loop {
747	            if p.starts("*/") || p.starts("//") {
748	                break;
749	            }
750	            p.ws();
751	            if p.rest().chars().next().is_some_and(|c| c.is_ascii_digit()) {
752	                let n: usize = p.digits().parse().unwrap();
753	                p.expect(".");
754	                assert_eq!(n, substitutions.len() + 1, "group numbering");
755	                substitutions.push(Vec::new());
756	                continue;
757	            }
758	            let lhs = p.term();
759	            p.expect("=");
760	            let rhs = p.term();
761	            substitutions
762	                .last_mut()
763	                .expect("substitution before group index")
764	                .push((lhs, rhs));
765	        }
766	    }
767	    if p.starts("//") {
768	        ac.loop_breakers = p.breaker_line();
769	    }
770	    p.expect("*/");
771	    (r, Some(AcVariants { ac_rule: ac, substitutions }))
772	}
