774	fn parse_restriction_block(block: &str) -> Restriction {
775	    let stmt_end = block.find("\n\n").expect("restriction comment separator");
776	    let stmt = &block[..stmt_end];
777	    let mut p = P::new(stmt);
778	    p.expect("restriction");
779	    p.ws();
780	    let name: String = p.rest().chars().take_while(|c| *c != ':').collect();
781	    p.pos += name.len();
782	    p.expect(":");
783	    p.expect("\"");
784	    let formula = p.formula();
785	    p.expect("\"");
786	    let _ = p.eat("// safety formula");
787	    let comment = &block[stmt_end..];
788	    let ex_hdr = "expanded formula:";
789	    let ex_idx = comment.find(ex_hdr).expect("expanded formula header");
790	    let mut pe = P::new(&comment[ex_idx + ex_hdr.len()..]);
791	    pe.expect("\"");
792	    let expanded = pe.formula();
793	    pe.expect("\"");
794	    Restriction { name, formula, expanded }
795	}
