797	fn parse_lemma_block(block: &str) -> (Lemma, Option<Guarded>) {
798	    let lines: Vec<&str> = block.lines().collect();
799	    let open = lines.iter().position(|l| *l == "/*").expect("guarded comment opener");
800	    let close = open + 1 + lines[open + 1..].iter().position(|l| *l == "*/").expect("guarded closer");
801	    let head = lines[..open].join("\n");
802	    let mut p = P::new(&head);
803	    p.expect("lemma");
804	    p.ws();
805	    let name: String = p
806	        .rest()
807	        .chars()
808	        .take_while(|c| !c.is_whitespace() && *c != '[' && *c != ':')
809	        .collect();
810	    p.pos += name.len();
811	    p.ws();

847	fn parse_macros_block(block: &str) -> Vec<Macro> {
848	    let mut p = P::new(block);
849	    p.expect("macros:");
850	    let mut out = Vec::new();
851	    loop {
852	        let name = p.ident();
853	        p.expect("(");
854	        let mut params = Vec::new();
855	        p.ws();
856	        if !p.rest().starts_with(')') {
857	            params.push(p.term());
858	            while p.eat(",") {
859	                params.push(p.term());
860	            }
861	        }
862	        p.expect(")");
863	        p.expect("=");
864	        let body = p.term();
865	        out.push(Macro { name, params, body });
866	        if !p.eat(",") {
867	            break;
868	        }
869	    }
870	    out
871	}
