873	fn parse_predicate_block(block: &str) -> Predicate {
874	    let mut p = P::new(block);
875	    p.expect("predicate:");
876	    let name = p.ident();
877	    p.expect("(");
878	    let mut params = Vec::new();
879	    p.ws();
880	    if !p.rest().starts_with(')') {
881	        params.push(p.binder());
882	        while p.eat(",") {
883	            params.push(p.binder());
884	        }
885	    }
886	    p.expect(")");
887	    p.expect("<=>");
888	    let body = p.formula();
889	    Predicate { name, params, body }
890	}
