892	/// Reconstruct the `Signature` from the declaration lines. builtins parsed from
893	/// the `builtins:` line (they induce no functions/equations, so they can't
894	/// perturb the merge); functions/equations parsed WHOLE and handed to the
895	/// renderer, which re-adds the base pairing symbols + equations, dedups and
896	/// re-sorts — reproducing the echo (the R1 closure is exercised on real input).
897	fn parse_signature(decls: &str) -> Signature {
898	    let lines: Vec<&str> = decls.lines().collect();
899	    let mut builtins = Vec::new();
900	    let mut functions = Vec::new();
901	    let mut equations = Vec::new();
902	    let mut convergent = false;
903	    let mut i = 0;
904	    while i < lines.len() {
905	        // A section = a col-0 header line + its indented continuation lines.
906	        let mut sect = String::from(lines[i]);
907	        let mut j = i + 1;
908	        while j < lines.len() && lines[j].starts_with(char::is_whitespace) {
909	            sect.push(' ');
910	            sect.push_str(lines[j].trim_start());
911	            j += 1;
912	        }
913	        if let Some(rest) = sect.strip_prefix("builtins:") {
914	            builtins = rest
915	                .split(',')
916	                .map(|s| s.trim().to_string())
917	                .filter(|s| !s.is_empty())
918	                .collect();
919	        } else if let Some(rest) = sect.strip_prefix("functions:") {
920	            functions = parse_function_items(rest);
921	        } else if let Some(rest) = sect.strip_prefix("equations") {
922	            let rest = rest.trim_start();
923	            let rest = if let Some(r) = rest.strip_prefix("[convergent]") {
924	                convergent = true;
925	                r.trim_start()
926	            } else {
927	                rest
928	            };
929	            let rest = rest.strip_prefix(':').expect("equations header colon");
930	            equations = parse_equations(rest);
931	        } else {
932	            panic!("unknown signature section: {sect:?}");
933	        }
