// ── envelope decoding (strict; mirrors producers-clean) ──────────────────────

fn decode_json_string(s: &str) -> (String, usize) {
    let bytes = s.as_bytes();
    let mut out = String::new();
    let mut i = 0;
    loop {
        match bytes[i] {
            b'"' => return (out, i),
            b'\\' => {
                i += 1;
                match bytes[i] {
                    b'"' => out.push('"'),
                    b'\\' => out.push('\\'),
                    b'/' => out.push('/'),
                    b'n' => out.push('\n'),
                    b't' => out.push('\t'),
                    b'r' => out.push('\r'),
                    b'b' => out.push('\u{8}'),
                    b'f' => out.push('\u{c}'),
                    b'u' => {
                        let cp = u32::from_str_radix(&s[i + 1..i + 5], 16).unwrap();
                        i += 4;
                        out.push(char::from_u32(cp).unwrap());
                    }
                    other => panic!("bad escape \\{}", other as char),
                }
                i += 1;
            }
            _ => {
                let c = s[i..].chars().next().unwrap();
                out.push(c);
                i += c.len_utf8();
            }
        }
    }
}

fn decode_envelope(raw: &str) -> (String, String) {
    let rest = raw.strip_prefix("{\"html\":\"").expect("html key");
    let (html, end) = decode_json_string(rest);
    let rest = rest[end..].strip_prefix("\",\"title\":\"").expect("title key");
    let (title, end) = decode_json_string(rest);
    assert_eq!(&rest[end..], "\"}", "envelope close");
    (html, title)
}

// ── skin inversion ───────────────────────────────────────────────────────────

const P_OPEN: &str = "<p class=\"monospace rules\">";

fn unpostprocess(html: &str) -> Vec<String> {
    assert!(html.ends_with("<br/>\n"), "postprocessed fragment");
    let mut lines: Vec<&str> = html.split("<br/>\n").collect();
    assert_eq!(lines.pop(), Some(""));
    lines
        .iter()
        .map(|line| {
            let mut rest = *line;
            let mut n = 0;
            while let Some(r) = rest.strip_prefix("&nbsp;") {
                rest = r;
                n += 1;
            }
            format!("{}{}", " ".repeat(n), rest)
        })
        .collect()
}

/// (leading_blank, [(heading, body_lines)]).
fn parse_blocks(lines: &[String]) -> (bool, Vec<(String, Vec<String>)>) {
    let mut i = 0;
    let leading_blank = lines.first().is_some_and(|l| l.is_empty());
    if leading_blank {
        i = 1;
    }
    let mut blocks = Vec::new();
    while i < lines.len() {
        let heading = lines[i]
            .strip_prefix("<h2>")
            .and_then(|h| h.strip_suffix("</h2>"))
            .unwrap_or_else(|| panic!("expected heading, got {:?}", lines[i]))
            .to_string();
        i += 1;
        let first = lines[i]
            .strip_prefix(P_OPEN)
            .unwrap_or_else(|| panic!("expected <p>, got {:?}", lines[i]));
        let mut body = Vec::new();
        let mut cur = first.to_string();
        loop {
            if let Some(stripped) = cur.strip_suffix("</p>") {
                if !(stripped.is_empty() && body.is_empty()) {
                    body.push(stripped.to_string());
                }
                i += 1;
                break;
            }
            body.push(cur);
            i += 1;
            cur = lines[i].clone();
        }
        blocks.push((heading, body));
    }
    (leading_blank, blocks)
}

fn strip_spans(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    let mut rest = s;
    while let Some(i) = rest.find('<') {
        out.push_str(&rest[..i]);
        let close = rest[i..].find('>').expect("span tag close") + i;
        let tag = &rest[i..=close];
        assert!(
            tag.starts_with("<span ") || tag == "</span>",
            "unexpected tag in body: {tag:?}"
        );
        rest = &rest[close + 1..];
    }
    out.push_str(rest);
    out
}

fn unescape(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    let mut rest = s;
    while let Some(i) = rest.find('&') {
        out.push_str(&rest[..i]);
        rest = &rest[i..];
        let (c, len) = if rest.starts_with("&amp;") {
            ('&', 5)
        } else if rest.starts_with("&lt;") {
            ('<', 4)
        } else if rest.starts_with("&gt;") {
            ('>', 4)
        } else if rest.starts_with("&quot;") {
            ('"', 6)
        } else if rest.starts_with("&#39;") {
            ('\'', 5)
        } else {
            panic!("unknown entity {:?}", &rest[..rest.len().min(8)]);
        };
        out.push(c);
        rest = &rest[len..];
    }
    out.push_str(rest);
    out
}

/// The captured body of a block as plain text (spans stripped, entities
/// unescaped, leading indent spaces preserved).
fn plain(body: &[String]) -> String {
    body.iter()
        .map(|l| unescape(&strip_spans(l)))
        .collect::<Vec<_>>()
        .join("\n")
}

// ── section reconstruction + re-render ───────────────────────────────────────

/// Split a plain-text section into blocks at col-0 lines matching `head`,
/// trimming the blank lines between blocks.
fn split_at_heads(plain: &str, head: &str) -> Vec<String> {
    let lines: Vec<&str> = plain.lines().collect();
    let starts: Vec<usize> = lines
        .iter()
        .enumerate()
        .filter(|(_, l)| l.starts_with(head))
        .map(|(i, _)| i)
        .collect();
    let mut out = Vec::new();
    for (k, &a) in starts.iter().enumerate() {
        let end = starts.get(k + 1).copied().unwrap_or(lines.len());
        let mut b = end;
        while b > a + 1 && lines[b - 1].is_empty() {
            b -= 1;
        }
        out.push(lines[a..b].join("\n"));
    }
    out
}

/// Re-render one message pane and return (rendered_body_per_section).
fn render_message(html: &str, title: &str) -> Vec<(String, String)> {
    assert_eq!(title, "Message theory");
    let (leading_blank, blocks) = parse_blocks(&unpostprocess(html));
    assert!(!leading_blank);
    let heads: Vec<&str> = blocks.iter().map(|(h, _)| h.as_str()).collect();
    assert_eq!(
        heads,
        ["Signature", "Construction Rules", "Deconstruction Rules"]
    );
    let mut out = Vec::new();
    for (h, body) in &blocks {
        let captured = body.join("\n");
        let pt = plain(body);
        let rendered = match h.as_str() {
            "Signature" => web::render_signature_body(&parse_signature(&pt)),
            "Construction Rules" | "Deconstruction Rules" => {
                let rules: Vec<_> = split_at_heads(&pt, "rule ")
                    .iter()
                    .map(|b| parse_bare_rule(b))
                    .collect();
                web::render_bare_rules_body(&rules)
            }
            other => panic!("unexpected message section {other}"),
        };
        out.push((h.clone(), captured));
        assert_eq!(rendered, out.last().unwrap().1, "message [{h}] body mismatch");
    }
    out
}

/// Re-render one rules pane; returns (leading_blank, [(heading, captured_body)])
/// for the whole-response reassembly, asserting each re-rendered section.
fn render_rules(html: &str, title: &str) -> (bool, Vec<(String, String)>) {
    assert_eq!(title, "Multiset rewriting rules and restrictions");
    let (leading_blank, blocks) = parse_blocks(&unpostprocess(html));
    let mut out = Vec::new();
    for (h, body) in &blocks {
        let captured = body.join("\n");
        let pt = plain(body);
        match h.as_str() {
            "Fact Symbols with Injective Instances" => {
                // Opaque producer input (None / L_x(id,?,?) …) — carried through,
                // not re-derived (documented in BEHAVIOR.md).
            }
            "Multiset Rewriting Rules" => {
                let rules: Vec<_> = split_at_heads(&pt, "rule ")
                    .iter()
                    .map(|b| parse_rule_block(b))
                    .collect();
                assert_eq!(web::render_msr_body(&rules), captured, "MSR body mismatch");
            }
            "Restrictions of the Set of Traces" => {
                let rs: Vec<_> = split_at_heads(&pt, "restriction ")
                    .iter()
                    .map(|b| parse_restriction_block(b))
                    .collect();
                assert_eq!(
                    web::render_restrictions_body(&rs),
                    captured,
                    "restrictions body mismatch"
                );
            }
            "Macros" => panic!("macros section unobserved in corpus — needs a live probe"),
            other => panic!("unexpected rules section {other}"),
        }
        out.push((h.clone(), captured));
    }
    (leading_blank, out)
}

// ── skin replica (for the whole-response byte check) ─────────────────────────

fn escape_heading(s: &str) -> String {
    s.replace('&', "&amp;")
        .replace('<', "&lt;")
        .replace('>', "&gt;")
        .replace('"', "&quot;")
        .replace('\'', "&#39;")
}

fn postprocess(assembled: &str) -> String {
    let mut out = String::new();
    for line in assembled.split('\n') {
        let text = line.trim_start_matches(' ');
        for _ in 0..line.len() - text.len() {
            out.push_str("&nbsp;");
        }
        out.push_str(text);
        out.push_str("<br/>\n");
    }
    out
}

fn json_escape(s: &str) -> String {
    let mut out = String::new();
    for c in s.chars() {
        match c {
            '"' => out.push_str("\\\""),
            '\\' => out.push_str("\\\\"),
            '\n' => out.push_str("\\n"),
            '\t' => out.push_str("\\t"),
            _ => out.push(c),
        }
    }
    out
}

/// Reassemble a pane the way producers `render_pane` does: `<h2>`/`<p>` block
/// skeleton (empty blocks per their mode), postprocess, `{html,title}` envelope.
fn reassemble(
    title: &str,
    leading_blank: bool,
    blocks: &[(&str, Option<&str>)], // (heading, Some(body) | None = omitted)
) -> String {
    let mut chunks: Vec<String> = Vec::new();
    if leading_blank {
        chunks.push(String::new());
    }
    for (heading, body) in blocks {
        let Some(body) = body else { continue };
        let mut chunk = String::new();
        chunk.push_str("<h2>");
        chunk.push_str(&escape_heading(heading));
        chunk.push_str("</h2>\n");
        chunk.push_str(P_OPEN);
        chunk.push_str(body);
        chunk.push_str("</p>");
        chunks.push(chunk);
    }
    let html = postprocess(&chunks.join("\n"));
    format!(
        "{{\"html\":\"{}\",\"title\":\"{}\"}}",
        json_escape(&html),
        json_escape(title)
    )
}

// ── the sweeps ───────────────────────────────────────────────────────────────

fn raw_files(suffix: &str) -> Vec<PathBuf> {
    let mut v: Vec<PathBuf> = fs::read_dir(raw_dir())
        .expect("R6 raw dir (materialize scratchpad/r6/raw)")
        .map(|e| e.unwrap().path())
        .filter(|p| p.to_str().unwrap().ends_with(suffix))
        .collect();
    v.sort();
    v
}

#[test]
fn message_pane_body_sweep() {
    let files = raw_files("__message.raw");
    assert!(files.len() >= 80, "expected ~82 message panes, got {}", files.len());
    let mut sections = 0;
    for path in &files {
        let raw = fs::read_to_string(path).unwrap();
        let (html, title) = decode_envelope(&raw);
        // Per-section re-render + assert (inside render_message).
        let rendered = render_message(&html, &title);
        sections += rendered.len();
        // Whole-response reassembly.
        let blocks: Vec<(&str, Option<&str>)> = rendered
            .iter()
            .map(|(h, b)| (h.as_str(), Some(b.as_str())))
            .collect();
        // Rebuild bodies from OUR renderer (already asserted equal to captured).
        let (_, parsed) = parse_blocks(&unpostprocess(&html));
        let my_bodies: Vec<String> = parsed
            .iter()
            .map(|(h, body)| match h.as_str() {
                "Signature" => web::render_signature_body(&parse_signature(&plain(body))),
                _ => {
                    let rules: Vec<_> = split_at_heads(&plain(body), "rule ")
                        .iter()
                        .map(|b| parse_bare_rule(b))
                        .collect();
                    web::render_bare_rules_body(&rules)
                }
            })
            .collect();
        let block_refs: Vec<(&str, Option<&str>)> = blocks
            .iter()
            .zip(&my_bodies)
            .map(|((h, _), b)| (*h, Some(b.as_str())))
            .collect();
        assert_eq!(
            reassemble(&title, false, &block_refs),
            raw,
            "message whole-response mismatch for {path:?}"
        );
    }
    assert_eq!(sections % 3, 0);
    eprintln!("message: {} panes, {sections} sections", files.len());
}

#[test]
fn rules_pane_body_sweep() {
    let files = raw_files("__rules.raw");
    assert!(files.len() >= 80, "expected ~82 rules panes, got {}", files.len());
    let mut msr = 0;
    let mut restr = 0;
    for path in &files {
        let raw = fs::read_to_string(path).unwrap();
        let (html, title) = decode_envelope(&raw);
        let (leading_blank, sections) = render_rules(&html, &title);
        for (h, _) in &sections {
            if h == "Multiset Rewriting Rules" {
                msr += 1;
            }
            if h == "Restrictions of the Set of Traces" {
                restr += 1;
            }
        }
        // Whole-response reassembly: re-render MSR/Restrictions from OUR path,
        // carry Fact Symbols opaque; Macros slot is the leading blank.
        let (_, parsed) = parse_blocks(&unpostprocess(&html));
        let mut blocks: Vec<(&str, Option<String>)> = Vec::new();
        for (h, body) in &parsed {
            let b = match h.as_str() {
                "Fact Symbols with Injective Instances" => body.join("\n"),
                "Multiset Rewriting Rules" => {
                    let rules: Vec<_> = split_at_heads(&plain(body), "rule ")
                        .iter()
                        .map(|x| parse_rule_block(x))
                        .collect();
                    web::render_msr_body(&rules)
                }
                "Restrictions of the Set of Traces" => {
                    let rs: Vec<_> = split_at_heads(&plain(body), "restriction ")
                        .iter()
                        .map(|x| parse_restriction_block(x))
                        .collect();
                    web::render_restrictions_body(&rs)
                }
                other => panic!("unexpected rules section {other}"),
            };
            blocks.push((h.as_str(), Some(b)));
        }
        let block_refs: Vec<(&str, Option<&str>)> =
            blocks.iter().map(|(h, b)| (*h, b.as_deref())).collect();
        assert_eq!(
            reassemble(&title, leading_blank, &block_refs),
            raw,
            "rules whole-response mismatch for {path:?}"
        );
    }
    eprintln!(
        "rules: {} panes, {msr} MSR sections, {restr} restriction sections",
        files.len()
    );
}

