use pretty_clean::doc::{nest, render_with, sep, sized_text, text, beside_op, Doc};

fn ann(d: Doc) -> Doc {
    // zero-width markers like web mode
    beside_op(sized_text(0, "\u{1}hl_operator\u{2}"), beside_op(d, sized_text(0, "\u{3}")))
}

